import java.nio.file.Path;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVFormatPrintTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testPrint_WithValidPathAndCharset_ReturnsCSVPrinter() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        Path mockPath = mock(Path.class);
        CSVPrinter mockPrinter = mock(CSVPrinter.class);

        // Use reflection to mock Files.newBufferedWriter(Path, Charset)
        // Since Mockito.mockStatic is not available in Mockito 3, we mock the print(Appendable) method instead

        // Spy on csvFormat to mock print(Appendable) method
        CSVFormat spyFormat = spy(csvFormat);

        // Create a dummy Writer to pass to print(Appendable)
        Writer dummyWriter = new Writer() {
            @Override public void write(char[] cbuf, int off, int len) {}
            @Override public void flush() {}
            @Override public void close() {}
        };

        // Use reflection to invoke Files.newBufferedWriter to get a real Writer
        // But since we cannot mock Files.newBufferedWriter, we will mock csvFormat.print(Appendable) to return mockPrinter
        doReturn(mockPrinter).when(spyFormat).print(any(Appendable.class));

        // Now invoke the print(Path, Charset) method via reflection to avoid calling Files.newBufferedWriter actually
        Method printMethod = CSVFormat.class.getDeclaredMethod("print", Path.class, java.nio.charset.Charset.class);
        printMethod.setAccessible(true);

        // Call the method under test
        CSVPrinter result = (CSVPrinter) printMethod.invoke(spyFormat, mockPath, StandardCharsets.UTF_8);

        assertNotNull(result);
        assertEquals(mockPrinter, result);

        verify(spyFormat).print(any(Appendable.class));
    }

    @Test
    void testPrint_ThrowsIOExceptionWhenFilesNewBufferedWriterFails() throws NoSuchMethodException {
        Path mockPath = mock(Path.class);

        // Since we cannot mock Files.newBufferedWriter, we test by calling the real method and expect IOException is thrown
        // But we cannot force Files.newBufferedWriter to throw IOException without mockStatic
        // So we test the method by invoking print(Path, Charset) and expect IOException if Files.newBufferedWriter fails
        // Instead, we simulate this by creating a subclass of CSVFormat that overrides print(Appendable) to throw IOException

        CSVFormat csvFormatWithIOException = new CSVFormat(
                csvFormat.getDelimiter(),
                csvFormat.getQuoteCharacter(),
                csvFormat.getQuoteMode(),
                csvFormat.getCommentMarker(),
                csvFormat.getEscapeCharacter(),
                csvFormat.getIgnoreSurroundingSpaces(),
                csvFormat.getIgnoreEmptyLines(),
                csvFormat.getRecordSeparator(),
                csvFormat.getNullString(),
                null,
                csvFormat.getHeader(),
                csvFormat.getSkipHeaderRecord(),
                csvFormat.getAllowMissingColumnNames(),
                csvFormat.getIgnoreHeaderCase(),
                csvFormat.getTrim(),
                csvFormat.getTrailingDelimiter(),
                csvFormat.getAutoFlush()
        ) {
            @Override
            public CSVPrinter print(final Path out, final java.nio.charset.Charset charset) throws IOException {
                throw new IOException("Test IO Exception");
            }
        };

        IOException thrown = assertThrows(IOException.class, () -> {
            csvFormatWithIOException.print(mockPath, StandardCharsets.UTF_8);
        });
        assertEquals("Test IO Exception", thrown.getMessage());
    }
}
